#include<bits/stdc++.h>
using namespace std;
int main(){
    int n,a[100005];
    cin>>n;
    long long ans=0;
    for(int i=1;i<=n;i++){
        cin>>a[i];
    }
    sort(a+1,a+1+n);
    for(int i=n;i>=1;i--){
        int temp=a[i];
        for(int j=2;j<=n-i+1;j++){
            if(temp==1){
                break;
            }else{
                temp=sqrt(temp);
            }
        }
        ans+=temp;
    }
    cout<<ans;
    return 0;
}
